def countAndSay(n: int) -> str:
    if n == 1:
        return "1"

    prev_seq = countAndSay(n - 1)

    result = []
    count = 1
    current_char = prev_seq[0]

    for i in range(1, len(prev_seq)):
        if prev_seq[i] == current_char:
            count += 1
        else:
            result.append(str(count))
            result.append(current_char)
            current_char = prev_seq[i]
            count = 1

    result.append(str(count))
    result.append(current_char)

    return "".join(result)
